```plantuml
@startuml
namespace com {
  namespace iluwatar {
    namespace prototype {
      class App {
        <<Concrete>>
        +App()
        +main(args : String[])
      }

      interface HeroFactory {
        <<Interface>>
        +createBeast() : Beast
        +createMage() : Mage
        +createWarlord() : Warlord
      }

      class HeroFactoryImpl {
        <<Concrete>>
        -beast : Beast
        -mage : Mage
        -warlord : Warlord
        +HeroFactoryImpl(mage : Mage, warlord : Warlord, beast : Beast)
        +createBeast() : Beast
        +createMage() : Mage
        +createWarlord() : Warlord
      }

      abstract class Prototype {
        <<Abstract>>
        +Prototype()
        +clone() : Object
      }

      abstract class Beast {
        <<Abstract>>
        +Beast()
        +clone() : Beast
      }

      abstract class Mage {
        <<Abstract>>
        +Mage()
        +clone() : Mage
      }

      abstract class Warlord {
        <<Abstract>>
        +Warlord()
        +clone() : Warlord
      }

      class ElfBeast {
        <<Concrete>>
        +ElfBeast()
        +clone() : Beast
        +toString() : String
      }

      class OrcBeast {
        <<Concrete>>
        +OrcBeast()
        +clone() : Beast
        +toString() : String
      }

      class ElfMage {
        <<Concrete>>
        +ElfMage()
        +clone() : Mage
        +toString() : String
      }

      class OrcMage {
        <<Concrete>>
        +OrcMage()
        +clone() : Mage
        +toString() : String
      }

      class ElfWarlord {
        <<Concrete>>
        +ElfWarlord()
        +clone() : Warlord
        +toString() : String
      }

      class OrcWarlord {
        <<Concrete>>
        +OrcWarlord()
        +clone() : Warlord
        +toString() : String
      }

      HeroFactoryImpl ..|> HeroFactory
      Beast --|> Prototype
      Mage --|> Prototype
      Warlord --|> Prototype
      ElfBeast --|> Beast
      OrcBeast --|> Beast
      ElfMage --|> Mage
      OrcMage --|> Mage
      ElfWarlord --|> Warlord
      OrcWarlord --|> Warlord
      HeroFactoryImpl --> "beast" Beast
      HeroFactoryImpl --> "mage" Mage
      HeroFactoryImpl --> "warlord" Warlord
    }
  }
}
@enduml
